import{_ as e,c as a,o,aR as t}from"./chunks/framework.MDQz7FCs.js";const b=JSON.parse('{"title":"Privacy Policy","description":"","frontmatter":{"title":"Privacy Policy","editLink":true},"headers":[],"relativePath":"privacy.md","filePath":"privacy.md","lastUpdated":1778480909000}'),i={name:"privacy.md"},r=t('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h1><p>Last updated: May 2024</p><p>This Privacy Policy describes how qrcode-with-logos (&quot;we&quot;, &quot;us&quot;, or &quot;our&quot;) collects, uses, and shares your information when you use our library and website.</p><h2 id="information-we-collect" tabindex="-1">Information We Collect <a class="header-anchor" href="#information-we-collect" aria-label="Permalink to &quot;Information We Collect&quot;">​</a></h2><h3 id="library-usage" tabindex="-1">Library Usage <a class="header-anchor" href="#library-usage" aria-label="Permalink to &quot;Library Usage&quot;">​</a></h3><p>The qrcode-with-logos library runs entirely in your browser or application. We do not collect, store, or transmit any QR code content, logos, or any data processed by the library. All QR code generation happens locally on your device.</p><h3 id="website-analytics" tabindex="-1">Website Analytics <a class="header-anchor" href="#website-analytics" aria-label="Permalink to &quot;Website Analytics&quot;">​</a></h3><p>Our documentation website may use analytics tools to collect standard information such as:</p><ul><li>IP address (anonymized)</li><li>Browser type and version</li><li>Pages visited</li><li>Time spent on pages</li><li>Referral sources</li></ul><p>This information is used solely to improve our documentation and understand how users interact with our website.</p><h2 id="how-we-use-information" tabindex="-1">How We Use Information <a class="header-anchor" href="#how-we-use-information" aria-label="Permalink to &quot;How We Use Information&quot;">​</a></h2><ul><li><strong>Library</strong>: No data is collected or transmitted</li><li><strong>Website</strong>: Analytics data is used to improve user experience and documentation quality</li></ul><h2 id="data-sharing" tabindex="-1">Data Sharing <a class="header-anchor" href="#data-sharing" aria-label="Permalink to &quot;Data Sharing&quot;">​</a></h2><p>We do not sell, trade, or otherwise transfer your personal information to third parties.</p><h2 id="cookies" tabindex="-1">Cookies <a class="header-anchor" href="#cookies" aria-label="Permalink to &quot;Cookies&quot;">​</a></h2><p>Our website may use cookies to enhance your browsing experience. You can choose to disable cookies through your browser settings.</p><h2 id="third-party-links" tabindex="-1">Third-Party Links <a class="header-anchor" href="#third-party-links" aria-label="Permalink to &quot;Third-Party Links&quot;">​</a></h2><p>Our website may contain links to third-party websites (such as GitHub, npm). These external sites have their own privacy policies, and we have no responsibility or liability for their content or activities.</p><h2 id="data-security" tabindex="-1">Data Security <a class="header-anchor" href="#data-security" aria-label="Permalink to &quot;Data Security&quot;">​</a></h2><p>Since the library operates entirely client-side and does not transmit data, your QR code content and logos remain on your device and are never sent to any external servers.</p><h2 id="your-rights" tabindex="-1">Your Rights <a class="header-anchor" href="#your-rights" aria-label="Permalink to &quot;Your Rights&quot;">​</a></h2><p>Depending on your jurisdiction, you may have the right to:</p><ul><li>Access any personal information we hold about you</li><li>Request correction of your personal information</li><li>Request deletion of your personal information</li><li>Object to processing of your personal information</li></ul><p>Note that since we don&#39;t collect personal data through the library, there may be no data to access or delete.</p><h2 id="children-s-privacy" tabindex="-1">Children&#39;s Privacy <a class="header-anchor" href="#children-s-privacy" aria-label="Permalink to &quot;Children&#39;s Privacy&quot;">​</a></h2><p>Our library and website are not intended for children under the age of 13. We do not knowingly collect personal information from children under 13.</p><h2 id="changes-to-this-privacy-policy" tabindex="-1">Changes to This Privacy Policy <a class="header-anchor" href="#changes-to-this-privacy-policy" aria-label="Permalink to &quot;Changes to This Privacy Policy&quot;">​</a></h2><p>We may update our Privacy Policy from time to time. We will notify you of any changes by posting the new Privacy Policy on this page and updating the &quot;Last updated&quot; date.</p><h2 id="contact-us" tabindex="-1">Contact Us <a class="header-anchor" href="#contact-us" aria-label="Permalink to &quot;Contact Us&quot;">​</a></h2><p>If you have any questions about this Privacy Policy, please contact us at:</p><p>📧 <strong><a href="mailto:zxpscau@163.com" target="_blank" rel="noreferrer">zxpscau@163.com</a></strong></p><p>Or through our GitHub repository: <a href="https://github.com/zxpsuper/qrcode-with-logos" target="_blank" rel="noreferrer">github.com/zxpsuper/qrcode-with-logos</a></p>',32),n=[r];function s(l,c,h,d,u,y){return o(),a("div",null,n)}const m=e(i,[["render",s]]);export{b as __pageData,m as default};
